import { hexToBigInt } from 'viem';
import {} from './types.js';
/**
 * Prepares a permit2 approval for signing via EIP-712.
 * @param permit2Approval The approval which has to be signed
 * @param quote The quote on which the intent is based
 * @param userAddress Address of the user creating the intent
 * @param deadline The deadline in which the swap must be fulfilled
 */
export const preparePermit2Approval = (permit2Approval, quote, userAddress, deadline) => {
    const permit2Data = permit2Approval.additional_data;
    const domain = {
        name: permit2Data.domain.name,
        // TODO: uncomment once domain on the smart contracts is fixed
        // version: permit2Data.domain.version ?? undefined,
        chainId: permit2Data.domain.chainId,
        verifyingContract: permit2Data.domain.verifyingContract,
    };
    const witness = {
        ...permit2Data.witness,
        ...(permit2Data.witness.minAmountOut
            ? {
                minAmountOut: hexToBigInt(permit2Data.witness.minAmountOut).toString(),
            }
            : {}),
        ...(permit2Data.witness.maxAmountOut
            ? {
                maxAmountOut: hexToBigInt(permit2Data.witness.maxAmountOut).toString(),
            }
            : {}),
        ...(permit2Data.witness.deadline
            ? { deadline: hexToBigInt(permit2Data.witness.deadline).toString() }
            : {}),
    };
    const message = {
        permitted: {
            token: quote.source_token,
            amount: quote.source_amount_lots,
        },
        spender: permit2Approval.escrow_contract_address,
        nonce: permit2Approval.nonce,
        deadline,
        witness,
    };
    return {
        domain,
        types: permit2Data.types,
        primaryType: 'PermitWitnessTransferFrom',
        message,
        account: userAddress,
    };
};
